&lt;li data-stringify-indent=&quot;0&quot; data-stringify-border=&quot;0&quot;&gt;Fully stocked kitchen and free on-site lunch daily&lt;/li&gt;
&lt;li data-stringify-indent=&quot;0&quot; data-stringify-border=&quot;0&quot;&gt;Season Ticket Loan Scheme&lt;/li&gt;
&lt;li data-stringify-indent=&quot;0&quot; data-stringify-border=&quot;0&quot;&gt;Tuition Reimbursement Program&lt;/li&gt;
